example.code:
plan_version: 2.4.0
events:
  - {name: checkout_started, properties: {plan_tier: string}, owner: growth, status: live}
  - {name: checkout_completed, properties: {order_id: string}, owner: growth, status: live}
metric_tree:
  north_star: weekly_active_paying_users
  inputs:
    - {name: activation_rate, causes: wapu}
    - {name: retention_d30, causes: wapu}
anomaly_rules:
  - {metric: activation_rate, threshold: 'wow_delta_abs > 0.03'}
pii_policy: {redact_at_ingest: true, fields: [email, phone, ip]}

plan_version: v1
events: [{name: ButtonClick, properties: {}}]
metric_tree: {north_star: DAU}
anomaly_rules: []
pii_policy: {redact_at_ingest: false}
